  export async function seedRequests(): Promise<void> {
    const dbUrl = process.env.DATABASE_URL
    if (!dbUrl) {
      console.error('[seed-requests] DATABASE_URL not set, skipping')
      return
    }

    const client = new pg.Client({ connectionString: dbUrl })
    await client.connect()

    try {
      const countResult = await client.query('SELECT count(*) FROM leave_requests')
      const existingCount = parseInt(countResult.rows[0].count, 10)
      if (existingCount >= requestData.length) {
        console.log(`[seed-requests] ${existingCount} leave requests already exist, skipping seed`)
        return
      }

      console.log(`[seed-requests] Found ${existingCount} requests, seeding ${requestData.length}...`)

      const ltRes = await client.query('SELECT id, code FROM leave_types')
      const codeToId: Record<string, number> = {}
      for (const r of ltRes.rows) codeToId[r.code] = r.id

      const userRes = await client.query('SELECT id, email FROM users WHERE is_active = true')
      const emailToId: Record<string, number> = {}
      for (const r of userRes.rows) emailToId[r.email] = r.id

      await client.query('BEGIN')
      let inserted = 0

      for (const r of requestData) {
        const userId = emailToId[r.email]
        const leaveTypeId = codeToId[r.leaveTypeCode]
        if (!userId || !leaveTypeId) continue

        const createdTs = r.createdAt ? r.createdAt + 'T00:00:00+00:00' : new Date().toISOString()

        const exists = await client.query(
          `SELECT id FROM leave_requests WHERE user_id = $1 AND leave_type_id = $2 AND start_date = $3 AND end_date = $4 AND total_days = $5`,
          [userId, leaveTypeId, r.startDate, r.endDate, r.totalDays]
        )
        if (exists.rows.length > 0) continue

        const res = await client.query(
          `INSERT INTO leave_requests (user_id, leave_type_id, start_date, end_date, total_days, reason, status, created_at, updated_at)
           VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $8)
           RETURNING id`,
          [userId, leaveTypeId, r.startDate, r.endDate, r.totalDays, r.reason || null, r.status, createdTs]
        )

        if (res.rows.length > 0) {
          const reqId = res.rows[0].id

          if ((r.status === 'approved' || r.status === 'cancelled') && r.approverEmail) {
            const approverId = emailToId[r.approverEmail]
            if (approverId) {
              const approvalStatus = r.status === 'approved' ? 'approved' : 'rejected'
              const actionDate = r.approvalDate ? r.approvalDate + 'T00:00:00+00:00' : createdTs
              await client.query(
                `INSERT INTO approval_workflows (leave_request_id, approver_id, level, status, action_date, created_at, updated_at)
                 VALUES ($1, $2, 1, $3, $4, $5, $5)`,
                [reqId, approverId, approvalStatus, actionDate, createdTs]
              )
            }
          }
          inserted++
        }
      }

      await client.query('COMMIT')
      console.log(`[seed-requests] Successfully seeded ${inserted} leave requests with approval workflows`)
    } catch (err) {
      await client.query('ROLLBACK').catch(() => {})
      console.error('[seed-requests] Error seeding requests:', err)
    } finally {
      await client.end()
    }
  }
  